"use strict";var config={comment:{mode:"btn",firstShowDelay:300,transitionDuration:1e3,commentTexts:["위치 에너지와 운동 에너지는 어떻게 변할까?"],commentHideDelay:[2e3],containerTransitionDuration:300},velocity:{min:"-12.0",max:"-20.0",initial:"-16.0",current:"-15.0"},mass:{min:"1.0",max:"11.0",initial:"6.0",current:"6.0"},timer:{playbackSpeed:1},constants:{graAcc:9.8},cannon:{areaHeight:465},pin:{maxLength:3,text:["A","B","C"],color:["#ffa03b","#ff6971","#9cba5f"]},graph:{areaHeight:300,barWidth:80,barMargin:25,tipHeight:30,barTransitionDuration:0},get maxDistance(){return-(Math.pow(this.velocity.max,2)/(2*this.constants.graAcc))},get cannonMeterPixelRatio(){return-this.cannon.areaHeight/this.maxDistance},get mechanicalE(){return this.mass.current*Math.pow(this.velocity.current,2)/2}};